_ICON_CACHE: dict[str, QIcon] = {}
_RENDERER_CACHE: dict[str, QSvgRenderer] = {}


def get_svg_renderer(name: IconName) -> QSvgRenderer:
    key = name.value
    if key not in _RENDERER_CACHE:
        svg_bytes = SVG_PATHS[name].encode("utf-8")
        _RENDERER_CACHE[key] = QSvgRenderer(svg_bytes)
    return _RENDERER_CACHE[key]


def icon(name: IconName, size: int = 24, color: str = "#000000") -> QIcon:
    cache_key = f"{name.value}_{size}_{color}"
    if cache_key in _ICON_CACHE:
        return _ICON_CACHE[cache_key]

    renderer = get_svg_renderer(name)
    pixmap = QPixmap(size, size)
    pixmap.fill(Qt.GlobalColor.transparent)

    painter = QPainter(pixmap)
    painter.setRenderHint(QPainter.RenderHint.Antialiasing)
    painter.setRenderHint(QPainter.RenderHint.SmoothPixmapTransform)
    renderer.render(painter)
    painter.setCompositionMode(QPainter.CompositionMode.CompositionMode_SourceIn)
    painter.fillRect(pixmap.rect(), QColor(color))
    painter.end()

    qicon = QIcon(pixmap)
    _ICON_CACHE[cache_key] = qicon
    return qicon


def icon_label(
    name: IconName,
    size: int = 24,
    color: str = "#000000",
) -> QLabel:
    lbl = QLabel()
    lbl.setPixmap(icon(name, size, color).pixmap(size, size))
    lbl.setFixedSize(size, size)
    lbl.setAlignment(Qt.AlignmentFlag.AlignCenter)
    return lbl
